arguments.command:
# Test: does BASH_COMMAND match cd with arguments?
bash -c '
hook() { echo "BASH_COMMAND=$BASH_COMMAND"; };
trap hook DEBUG;
cd /tmp;
cd;
cd -;
cd ~/;
' 2>/dev/null | head -20

# Test: BASH_COMMAND guard correctly filters non-cd commands
bash -c '
hook() {
  [[ "$BASH_COMMAND" == cd* ]] && echo "MATCHED: $BASH_COMMAND"
};
trap hook DEBUG;
echo hello;
ls /tmp;
cd /tmp;
pwd;
' 2>/dev/null

# Test: does cd* pattern match commands starting with 'cd' but not being 'cd'?
bash -c '
hook() {
  [[ "$BASH_COMMAND" == cd* ]] && echo "MATCHED: [$BASH_COMMAND]"
};
trap hook DEBUG;
cdpath_test 2>/dev/null;
cdsomevar=1;
' 2>/dev/null | grep MATCHED

# Verify the regex-based fix works correctly
bash -c '
hook() {
  [[ "$BASH_COMMAND" =~ ^cd(\ |$) ]] && echo "MATCHED: [$BASH_COMMAND]"
};
trap hook DEBUG;
cd /tmp;
cd;
cd -;
cdpath_test 2>/dev/null;
cdsomevar=1;
cd-command 2>/dev/null;
' 2>/dev/null | grep MATCHED
